sql:
SELECT u.user_name, p.portfolio_name, p.risk_level
FROM portfolios p
JOIN users u ON p.user_id = u.user_id
WHERE p.total_value = (
    SELECT MAX(total_value) FROM portfolios
);

SELECT last_trade_price, market_cap, company_name
FROM stocks
WHERE ticker_symbol = 'GOOG';
